ValidationRule.errorConditionFormula:
AND(
	OR(
		ISBLANK(Start_Date_INF__c),
		ISBLANK( End_Date_INF__c)
	),
	OR(
		CONTAINS(PricebookEntry.Product2.Name,'Subscription'),CONTAINS(PricebookEntry.Product2.Name,'Maintenance'),CONTAINS(PricebookEntry.Product2.Name,'Term')
	),
	Product2.Business_Unit__c == 'INF' 
)
